import { useRef, useEffect } from 'react';

function useEffectOnce(cb, deps) {
  const mountRef = useRef(false);
  useEffect(() => {
    let returnValue;
    if (mountRef.current === false) {
      returnValue = cb();
      mountRef.current = true;
    }
    return returnValue;
  }, [deps]);
}

export { useEffectOnce };
